import React from "react";

const ContenedorLateral = ({ subtitulo, texto, imagen, ancho, alto, borderRadiusOval = "full", borderRadiusContenedor = "2xl" }) => {
  return (
    <div
      className="relative mt-5 bg-black p-6 flex flex-col items-center justify-start z-10 shadow-2xl"
      style={{
        width: ancho, // Usamos el prop para el ancho
        height: alto, // Usamos el prop para el alto
        borderRadius: `var(--tw-border-radius-${borderRadiusContenedor})`, // Usamos el prop para redondear el contenedor
      }}
    >
      {/* Subtítulo en óvalo blanco */}
      <div
        className="absolute bg-white px-6 py-2 text-sm font-semibold shadow text-black"
        style={{
          top: `-5%`, // Mover el óvalo ligeramente hacia arriba o abajo de manera proporcional
          left: "50%",
          transform: "translateX(-50%)", // Centrado automático
          borderRadius: `var(--tw-border-radius-${borderRadiusOval})`, // Redondez del óvalo
          fontSize: "clamp(0.75rem, 2vw, 1rem)", // Tamaño de fuente dinámico
          padding: "clamp(0.5rem, 2vw, 1rem)", // Padding dinámico
        }}
      >
        {subtitulo}
      </div>

      {/* Contenido dentro del contenedor */}
      <div className="mt-8 w-full text-white text-sm text-center space-y-6">
        <p className="leading-relaxed text-xs sm:text-sm md:text-base lg:text-lg">{texto}</p>

        <div className="flex justify-center">
          <img
            src={imagen}
            alt="contenido dinámico"
            className="rounded-lg object-contain max-w-[90%] max-h-[30vh]"
          />
        </div>
      </div>
    </div>
  );
};

export default ContenedorLateral;
